package cn.itcraft.jxlsb.format;

import java.util.Base64;

/**
 * 使用标准Excel样式模板
 * 该模板来自WPS生成的XLSB文件，包含完整的字体、填充、边框和样式定义
 */
public final class StylesWriter {
    
    private static final String TEMPLATE_BASE64 = 
        "";
    
    public byte[] toBiff12Bytes() {
        return Base64.getDecoder().decode(TEMPLATE_BASE64);
    }
}